// ─────────────────────────────────────────────
// SAP Response Simulator (Standard Body)
// Body ALWAYS:
//   { success: boolean, message: string, errors: [] }
// ─────────────────────────────────────────────

function makeResponse(statusCode, success, message, errors) {
    msg.statusCode = statusCode;
    msg.headers = msg.headers || {};
    msg.headers["Content-Type"] = "application/json; charset=utf-8";

    msg.payload = {
        success,
        message,
        errors: errors || []
    };
    return msg;
}

// Helper to build an error object
function err(code, message, source, extra) {
    const e = { code, message };
    if (source) e.source = source;
    if (extra && typeof extra === "object") Object.assign(e, extra);
    return e;
}

// ─────────────────────────────────────────────
// CONFIG: EDIT PERCENTAGES HERE (must sum to 100)
// ─────────────────────────────────────────────
const PCT = {
    OK_200: 70,

    INVALID_PAYLOAD_400: 10,
    NO_PROD_ORDERS_400: 5,

    UNDERWEIGHT_422: 5,
    OVERWEIGHT_422: 5,

    CRITICAL_500: 2,
    SAP_CONFIG_500: 1,
    SAP_CONNECT_500: 1,

    SAP_UNAVAILABLE_503: 1
};

// Optional safety check (warn in debug if not 100)
const total = Object.values(PCT).reduce((a, b) => a + b, 0);
if (total !== 100) {
    node.warn(`PCT total is ${total} (should be 100). Adjust your percentages.`);
}

// ─────────────────────────────────────────────
// RANDOM PICK (0..100)
// ─────────────────────────────────────────────
const r = Math.random() * 100;

// Build cumulative thresholds so you can edit PCT freely
let t = 0;
function hit(p) { t += p; return r < t; }

if (hit(PCT.OK_200)) {
    return makeResponse(
        200,
        true,
        "Request processed successfully",
        []
    );
}

if (hit(PCT.INVALID_PAYLOAD_400)) {
    return makeResponse(
        400,
        false,
        "Invalid payload",
        [err("INVALID_PAYLOAD", "Payload validation failed", "API")]
    );
}

if (hit(PCT.NO_PROD_ORDERS_400)) {
    return makeResponse(
        400,
        false,
        "No production orders provided",
        [err("NO_PRODUCTION_ORDERS", "No production orders provided", "API")]
    );
}

if (hit(PCT.UNDERWEIGHT_422)) {
    return makeResponse(
        422,
        false,
        "Measured weight is below the allowed minimum",
        [
            err(
                "WEIGHT_UNDER",
                "Measured weight is below the allowed minimum",
                "SCALE",
                { minAllowed: 5.0, actual: 3.2 }
            )
        ]
    );
}

if (hit(PCT.OVERWEIGHT_422)) {
    return makeResponse(
        422,
        false,
        "Measured weight exceeds the allowed maximum",
        [
            err(
                "WEIGHT_OVER",
                "Measured weight exceeds the allowed maximum",
                "SCALE",
                { maxAllowed: 30.0, actual: 42.7 }
            )
        ]
    );
}

if (hit(PCT.CRITICAL_500)) {
    return makeResponse(
        500,
        false,
        "Critical failure",
        [err("CRITICAL_FAILURE", "Critical failure occurred", "API")]
    );
}

if (hit(PCT.SAP_CONFIG_500)) {
    return makeResponse(
        500,
        false,
        "SAP configuration missing",
        [err("SAP_CONFIG_MISSING", "SAP settings are missing", "API")]
    );
}

if (hit(PCT.SAP_CONNECT_500)) {
    return makeResponse(
        500,
        false,
        "Failed to connect to SAP B1",
        [err("SAP_CONNECT_FAILED", "Failed to connect to SAP Business One", "SAP")]
    );
}

// Fallback (whatever is left) -> 503 SAP unavailable
return makeResponse(
    503,
    false,
    "SAP service unavailable",
    [err("SAP_UNAVAILABLE", "Failed to connect to SAP B1", "SAP")]
);

// Random 13-digit prefix, incrementing 5-digit suffix (global suffix)
const CRLF = "\r\n";

let state = flow.get('barcode_state') || {
    suffix: 1
};

// 🔥 generate a NEW random 13-digit prefix every time
const prefix = String(Math.floor(1e12 + Math.random() * 9e12));

// format suffix
let suffixStr = String(state.suffix).padStart(5, '0');

// build barcode
let barcode = `${prefix}-${suffixStr}${CRLF}`;

// increment suffix
state.suffix += 1;
if (state.suffix > 99999) state.suffix = 1;

// save state
flow.set('barcode_state', state);

// output
msg.payload = barcode;
return msg;

// Expects command: W<CR><LF>
// TCP node splits on \n and trims, so payload becomes "W" or "W\r"

const CRLF = "\r\n";

let cmd = (msg.payload ?? "").toString();
cmd = cmd.replace(/\r/g, "").trim().toUpperCase();

if (cmd !== "W") {
    // ignore anything else
    return null;
}

// Random weight (choose range you want)
// Example: 0.00 to 999.99
const weight = Math.random() * 999.99;

// Format: +024.36 (3 digits before decimal, 2 decimals)
const formatted = "+" + weight.toFixed(2).padStart(6, "0");

msg.payload = formatted + CRLF;
return msg;

// Increment API hit counter

let count = flow.get("api_hit_count") || 0;
count += 1;
flow.set("api_hit_count", count);

// Optional: expose count on the message
msg.apiHitCount = count;

// Optional: show in node status (very handy)
node.status({
    fill: "green",
    shape: "dot",
    text: `API hits: ${count}`
});

return msg;

const minEntriesPerBlock = 4;
const maxEntriesPerBlock = 5;

const fixedDelayMs = 15000;
const wrapAt9999 = true;

// Chance to prepend a random alphanumeric character
const pFiveCharCode = 0.5; // 30%

// Framing characters
const STX = "\x02";
const ETX = "\x03";

// Fixed third field
const FIXED_B_TEXT = "InboundScanning1JBH";

// -------------------- helpers --------------------

function randInt(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
}

function rand4int() {
    return randInt(0, 9999);
}

function fmt4(n) {
    return n.toString().padStart(4, "0");
}

function inc4(n) {
    return wrapAt9999 ? (n + 1) % 10000 : Math.min(n + 1, 9999);
}

function randAlphaNumChar() {
    const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
    return chars.charAt(randInt(0, chars.length - 1));
}

// -------------------- timer utils --------------------

function clearAllTimers() {
    const timers = context.get("timers") || [];
    for (const t of timers) clearTimeout(t);
    context.set("timers", []);
}

function schedule(fn, delayMs) {
    const t = setTimeout(fn, delayMs);
    const arr = context.get("timers") || [];
    arr.push(t);
    context.set("timers", arr);
    return t;
}

// -------------------- send helpers --------------------

function sendFramed(line) {
    node.send({ payload: STX + line + ETX });
}

// Build code: "0123" OR "X0123"
function buildCode(a4) {
    if (Math.random() < pFiveCharCode) {
        return randAlphaNumChar() + a4;
    }
    return a4;
}

// Send data line + update camera globals
function sendDataLine(prefix, a4) {
    const code = buildCode(a4);

    // Publish for camera to mirror
    global.set("camera_code", code);

    const line = `${prefix}|${code}|${FIXED_B_TEXT}`;
    global.set("camera_last_server_line", line);

    sendFramed(line);
}

function sendLoadClosed(prefix) {
    const line = `Load_Closed|${prefix}`;
    global.set("camera_last_server_line", line);
    global.set("camera_code", null);

    sendFramed(line);
}

// -------------------- main logic --------------------

clearAllTimers();
context.set("running", false);

let blockNum = context.get("blockNum");
if (typeof blockNum !== "number") blockNum = 1;

function startBlock() {
    context.set("running", true);

    const prefix = blockNum;
    const entries = randInt(minEntriesPerBlock, maxEntriesPerBlock);

    let a = rand4int();
    let t = 0;

    // First line
    sendDataLine(prefix, fmt4(a));

    // Remaining lines
    for (let i = 2; i <= entries; i++) {
        t += fixedDelayMs;
        schedule(() => {
            a = inc4(a);
            sendDataLine(prefix, fmt4(a));
        }, t);
    }

    // Load Closed
    t += fixedDelayMs;
    schedule(() => sendLoadClosed(prefix), t);

    // Next block
    t += fixedDelayMs;
    schedule(() => {
        blockNum += 1;
        context.set("blockNum", blockNum);
        clearAllTimers();
        startBlock();
    }, t);
}

// Kick off once on deploy
if (!context.get("running")) {
    startBlock();
}

return null;

