const tickMs = 1000;

const pNoRead = 0.01; // 10%
const pCorrupt = 0.01; // 10% (one message only)

const STX = "\x02";
const ETX = "\x03";

function randInt(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
}

function randDigits(n) {
    let s = "";
    for (let i = 0; i < n; i++) s += randInt(0, 9).toString();
    return s;
}

function isValidCode(code) {
    // "0123" or "a0123" (letter + 4 digits)
    return typeof code === "string" && (/^\d{4}$/.test(code) || /^[A-Za-z]\d{4}$/.test(code));
}

function corruptCode(code) {
    // corrupt only the numeric part (keep letter if present)
    let letter = "";
    let digits = code;

    if (/^[A-Za-z]\d{4}$/.test(code)) {
        letter = code[0];
        digits = code.slice(1);
    }

    // make different 4-digit number
    let bad = randInt(0, 9999).toString().padStart(4, "0");
    if (bad === digits) bad = ((parseInt(bad, 10) + 1) % 10000).toString().padStart(4, "0");

    return letter + bad;
}

function send(payloadStr) {
    node.send({ payload: STX + payloadStr + ETX });
}

// Stop existing interval on redeploy
let interval = context.get("interval");
if (interval) {
    clearInterval(interval);
    context.set("interval", null);
}

function tick() {
    // If server last sent Load_Closed|X, mirror it
    const lastLine = String(global.get("camera_last_server_line") || "");
    if (lastLine.startsWith("Load_Closed|")) {
        send(lastLine);
        return;
    }

    // Otherwise, mirror the exact code the server sent
    const code = global.get("camera_code");

    if (!isValidCode(code)) {
        // nothing to mirror yet
        return;
    }

    const r = Math.random();

    if (r < pNoRead) {
        send("NoRead");
        return;
    }

    const finalCode = (r < (pNoRead + pCorrupt)) ? corruptCode(code) : code;

    // Barcode = code (4 or 5 chars) + 13 digits
    send(finalCode + randDigits(13));
}

interval = setInterval(tick, tickMs);
context.set("interval", interval);

// Fire one immediately
setTimeout(tick, 0);

return null;

